import json, uuid

AGENT_DEF = """${agent_definition}""".strip()
INSTANCE = """${instance_name}""".strip() or AGENT_DEF
LLM_SERVICE = """${llm_service}""".strip()
MODEL = """${model}""".strip()
MAX_DEPTH = int("""${max_depth}""".strip() or "1")
TTL = int("""${conv_ttl_seconds}""".strip() or "3600")
TIMEOUT = float("""${response_timeout_seconds}""".strip() or "120")
SKILLS = [s.strip() for s in """${skills}""".split(",") if s.strip()]
TOOLS = [t.strip() for t in """${tools}""".split(",") if t.strip()] or ["web_search", "fetch", "read"]
ALLOWED_ORIGIN = """${allowed_origin}""".strip()
MAX_COST = float("""${max_cost}""".strip() or "0")
BUDGET_VAR = """${budget_var}""".strip() or "web_help_budget_used"
COOKIE_NAME = """${cookie_name}""".strip() or "pf_help_sid"


def _respond(status, payload, set_cookie=""):
    flowfile.set_attribute("http.response.status", str(status))
    flowfile.set_attribute("http.response.header.Content-Type", "application/json")
    if ALLOWED_ORIGIN:
        flowfile.set_attribute("http.response.header.Access-Control-Allow-Origin", ALLOWED_ORIGIN)
        flowfile.set_attribute("http.response.header.Vary", "Origin")
    if set_cookie:
        flowfile.set_attribute("http.response.header.Set-Cookie", set_cookie)
    return json.dumps(payload)


origin = attributes.get("http.header.origin", "")
if ALLOWED_ORIGIN and origin != ALLOWED_ORIGIN:
    result = _respond(403, {"error": "forbidden"})
else:
    try:
        body = json.loads(content or "{}")
    except Exception:
        body = {}
    text = str(body.get("message", "")).strip()

    cookie_hdr = attributes.get("http.header.cookie", "")
    sid = ""
    for part in cookie_hdr.split(";"):
        part = part.strip()
        if part.startswith(COOKIE_NAME + "="):
            sid = part[len(COOKIE_NAME) + 1:]
            break
    new_cookie = ""
    if not sid:
        sid = uuid.uuid4().hex
        new_cookie = (COOKIE_NAME + "=" + sid +
                      "; Path=/api/help; HttpOnly; SameSite=Strict; Secure; Max-Age=" + str(TTL))

    if not text:
        result = _respond(400, {"error": "empty message"}, new_cookie)
    else:
        try:
            used = float(pawflow.get_variable(BUDGET_VAR, "0") or 0)
        except Exception:
            used = 0.0
        if MAX_COST > 0 and used >= MAX_COST:
            result = _respond(503, {"error": "The help bot is temporarily unavailable. Please try again later."}, new_cookie)
        else:
            key = INSTANCE + ":" + sid
            cid = ""
            for c in pawflow.find_conversations("help_bot_web_key", key):
                if pawflow.is_conversation_expired(c):
                    pawflow.delete_conversation(c)
                else:
                    cid = c
                    break
            if not cid:
                cid = pawflow.create_conversation(
                    agents=[{
                        "instance_name": INSTANCE,
                        "definition": AGENT_DEF,
                        "llm_service": LLM_SERVICE,
                        "params": {"name": INSTANCE},
                        "model": MODEL,
                        "tools": TOOLS,
                        "max_depth": MAX_DEPTH,
                        "skills": SKILLS,
                    }],
                    title="Web help - " + sid[:8],
                    relays=[],
                    ttl=TTL,
                )
                pawflow.set_extra(cid, "help_bot_web_key", key)
                pawflow.set_tool_filters(cid, INSTANCE, TOOLS)
            else:
                pawflow.set_conversation_ttl(cid, TTL)

            res = pawflow.run_agent(
                cid, INSTANCE, text,
                timeout=TIMEOUT,
                channel="web",
                source_attributes={"web.session": sid},
            )
            try:
                pawflow.increment_variable(BUDGET_VAR, float(res.get("cost_usd") or 0.0))
            except Exception:
                pass
            if res.get("timed_out"):
                result = _respond(504, {"error": "Sorry, this took too long. Please try again."}, new_cookie)
            elif res.get("error"):
                result = _respond(500, {"error": res["error"]}, new_cookie)
            else:
                result = _respond(200, {"response": res.get("response", "") or ""}, new_cookie)

deleted = 0
for conv in pawflow.list_conversations():
    cid = conv.get("conversation_id") or ""
    if not cid:
        continue
    if not pawflow.get_extra(cid, "help_bot_web_key"):
        continue
    if pawflow.is_conversation_expired(cid):
        pawflow.delete_conversation(cid)
        deleted += 1
result = "swept " + str(deleted)
